reg [7:0] data;
generate
genvar i;
for (i = 0; i <= 7; i = i + 1) begin
    always @(posedge clk)
        data[i] <= a[i] & b[i];
end
endgenerate

reg [7:0] data;
output logic [7:0] out;
// data bits driven bit-by-bit elsewhere
always @(posedge clk)
    out <= ~data;

module part__0(clk, a, b, data, n1);
  input clk;
  input [7:0] a, b;
  inout [7:0] data;
  wire [7:0] data;
  reg data_reg2;
  always @(posedge clk)
    data_reg2 <= a[2] & b[2];
  assign data[2] = data_reg2;
endmodule

wire [7:0] data;
part__0 u0 (
    .data({ w7, w6, w5, w4, w3, data[2], w1, w0 })
);
